const evolutionBaseUrl = 'REPLACE_WITH_EVOLUTION_BASE_URL';
const evolutionInstance = 'REPLACE_WITH_EVOLUTION_INSTANCE';
const evolutionApiKey = 'REPLACE_WITH_EVOLUTION_API_KEY';
const supabaseUrl = 'REPLACE_WITH_SUPABASE_URL';
const supabaseKey = 'REPLACE_WITH_SUPABASE_ANON_OR_SERVICE_KEY';

const normalizeLeadId = (value) => String(value || '').split('@')[0].trim();
const isIgnorableChat = (remoteJid) => !remoteJid || remoteJid.endsWith('@g.us') || remoteJid.includes('@newsletter') || remoteJid === 'status@broadcast';
const mergeLabels = (existingLabels = [], incomingLabels = []) => {
  const merged = new Map();
  for (const label of [...existingLabels, ...incomingLabels]) {
    if (!label?.id) continue;
    merged.set(String(label.id), {
      id: String(label.id),
      name: String(label.name || ''),
      color: String(label.color || '0'),
    });
  }
  return Array.from(merged.values()).sort((a, b) => a.name.localeCompare(b.name));
};
const requestJson = async (url, options = {}) => {
  const response = await fetch(url, options);
  const text = await response.text();
  if (!response.ok) {
    throw new Error(`Request failed ${response.status}: ${text.slice(0, 500)}`);
  }
  return text ? JSON.parse(text) : null;
};

const chats = await requestJson(`${evolutionBaseUrl}/chat/findChats/${evolutionInstance}`, {
  method: 'POST',
  headers: {
    apikey: evolutionApiKey,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({
    take: 500,
    include: { labels: true },
  }),
});

const labeledChats = (chats || []).filter((chat) => !isIgnorableChat(chat.remoteJid) && Array.isArray(chat.labels) && chat.labels.length > 0);
const existingLeads = await requestJson(`${supabaseUrl}/rest/v1/Leads?select=id,lead_id,lead_nome,labels,chatbot_ativo&limit=5000`, {
  headers: {
    apikey: supabaseKey,
    Authorization: `Bearer ${supabaseKey}`,
  },
});
const existingLeadMap = new Map((existingLeads || []).map((lead) => [normalizeLeadId(lead.lead_id), lead]));

let syncedLeads = 0;
for (const chat of labeledChats) {
  const leadId = normalizeLeadId(chat.remoteJid);
  const existingLead = existingLeadMap.get(leadId);
  const payload = {
    lead_id: leadId,
    lead_nome: existingLead?.lead_nome && existingLead.lead_nome !== 'Sem nome' ? existingLead.lead_nome : ((chat.pushName || '').trim() || 'Sem nome'),
    labels: mergeLabels(existingLead?.labels, chat.labels),
    chatbot_ativo: existingLead?.chatbot_ativo ?? true,
  };

  await requestJson(`${supabaseUrl}/rest/v1/Leads`, {
    method: 'POST',
    headers: {
      apikey: supabaseKey,
      Authorization: `Bearer ${supabaseKey}`,
      'Content-Type': 'application/json',
      Prefer: 'resolution=merge-duplicates,return=minimal',
    },
    body: JSON.stringify(payload),
  });

  syncedLeads += 1;
}

return [{
  json: {
    chatsScanned: (chats || []).length,
    labeledChats: labeledChats.length,
    syncedLeads,
    note: labeledChats.length === 0 ? 'A Evolution nao retornou labels associadas nos chats. Sem dados para backfill.' : 'Labels sincronizadas com sucesso.',
  },
}];
